// ── Server-side validation ─────────────────────────────────
// Clinic identity is resolved server-side. In clinic_qr mode it comes from
// intake_token. In shared_qr mode it comes from the selected hospital+doctor.

const body = $input.first().json.body || $input.first().json;

const errors = [];
const clean = (value, max = 1000) => String(value || '').trim().slice(0, max);

const patientName = clean(body.patient_name, 100);
const phoneRaw    = clean(body.phone_number, 20);
const dob         = clean(body.dob, 20);
const sex         = clean(body.sex, 20);
const intakeToken = clean(body.intake_token || body.intakeToken, 80).toLowerCase();
const hospitalName = clean(body.hospital_name, 180);
const clinicMode  = ['clinic_qr', 'shared_qr'].includes(clean(body.clinic_mode || body.clinicMode, 40).toLowerCase())
  ? clean(body.clinic_mode || body.clinicMode, 40).toLowerCase()
  : (intakeToken ? 'clinic_qr' : 'shared_qr');
const doctorName  = clean(body.doctor_name, 160);
const visitDate   = clean(body.visit_date, 20);

const ISO_DATE = /^\d{4}-\d{2}-\d{2}$/;
const PHONE_RE = /^[0-9]{10}$/;
const timezone = $env.TIMEZONE || 'Asia/Kolkata';
const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: timezone });

function rateLimitRequest(scope, key, limit, windowMs) {
  if (!key) return null;
  try {
    const store = typeof $getWorkflowStaticData === 'function' ? $getWorkflowStaticData('global') : null;
    if (!store) return null;
    store._rateLimits = store._rateLimits || {};
    const now = Date.now();
    const bucketKey = scope + ':' + key;
    const bucket = Array.isArray(store._rateLimits[bucketKey]) ? store._rateLimits[bucketKey] : [];
    const recent = bucket.filter(ts => now - ts < windowMs);
    recent.push(now);
    store._rateLimits[bucketKey] = recent;
    return recent.length > limit ? Math.ceil((windowMs - (now - recent[0])) / 1000) : null;
  } catch (_) {
    return null;
  }
}

const headers = $input.first().json.headers || {};
const header = name => headers[name] || headers[name.toLowerCase()] || headers[name.toUpperCase()] || '';
const clientIp = String(header('x-forwarded-for') || header('x-real-ip') || 'unknown').split(',')[0].trim();
const ipRetryAfter = rateLimitRequest('patient-form-ip', clientIp, 80, 15 * 60 * 1000);
const phoneRetryAfter = PHONE_RE.test(phoneRaw) ? rateLimitRequest('patient-form-phone', phoneRaw, 8, 15 * 60 * 1000) : null;
if (ipRetryAfter || phoneRetryAfter) errors.push('too_many_requests: please wait before submitting again');

if (!patientName || patientName.length < 2) errors.push('patient_name: required, minimum 2 characters');
if (!PHONE_RE.test(phoneRaw)) errors.push('phone_number: must be exactly 10 digits (no +91)');
if (clinicMode === 'clinic_qr' && (!intakeToken || !/^[a-f0-9]{64}$/.test(intakeToken))) errors.push('intake_token: valid clinic QR token is required');
if (clinicMode === 'shared_qr' && !hospitalName) errors.push('hospital_name: required for shared QR mode');
if (!doctorName) errors.push('doctor_name: required');
if (!visitDate || !ISO_DATE.test(visitDate)) errors.push('visit_date: required, format YYYY-MM-DD');
else if (visitDate > todayStr) errors.push('visit_date: cannot be in the future');

if (sex && !['Male','Female','Other'].includes(sex)) errors.push('sex: must be Male, Female, or Other');

if (dob) {
  if (!ISO_DATE.test(dob)) errors.push('dob: format must be YYYY-MM-DD');
  else if (dob >= todayStr) errors.push('dob: must be a past date');
}

if (errors.length > 0) return [{ json: { _valid: false, _errors: errors } }];

const phone = '+91' + phoneRaw;

return [{
  json: {
    _valid: true,
    _errors: [],
    patient_name: patientName,
    phone,
    dob: dob || null,
    sex: sex || null,
    intake_token: intakeToken,
    clinic_mode: clinicMode,
    hospital_name: hospitalName,
    doctor_name: doctorName,
    visit_date: visitDate,
    clinic_name: hospitalName,
  }
}];

// Pull validated fields from the Validate node and server-resolved clinic.
const v = $('Validate and Normalise').first().json;
const resolved = $input.first().json || {};

if (!resolved.token_valid || !resolved.clinic_id) {
  const source = v.clinic_mode === 'shared_qr' ? 'selected clinic and doctor' : 'intake token';
  return [{ json: { _valid: false, _errors: [source + ': invalid, inactive, or doctor is not linked to this clinic'] } }];
}

return [{
  json: {
    _valid: true,
    patient_code: null,
    name: v.patient_name,
    phone: v.phone,
    dob: v.dob,
    sex: v.sex,
    clinic_name: resolved.hospital_name,
    clinic_id: resolved.clinic_id,
    doctor_name: v.doctor_name,
    visit_date: v.visit_date,
    follow_up_required: 'No',
    follow_up_date: null,
  }
}];

const v = $('Validate and Normalise').first().json;
const count = $('Get Patient Count').first().json.total || 0;
const resolved = $('Resolve Clinic (Shared)').first().json || {};
const patientCode = 'PAT-' + String(count + 1).padStart(4, '0');
return [{
  json: {
    patient_code: patientCode,
    clinic_id: resolved.clinic_id || null,
    name: v.patient_name,
    phone: v.phone,
    dob: v.dob,
    sex: v.sex,
    clinic_name: v.clinic_name || v.hospital_name,
    doctor_name: v.doctor_name,
    visit_date: v.visit_date,
    follow_up_required: 'No',
    follow_up_date: null,
  }
}];

function first(nodeName) {
  try { return $(nodeName).first().json || {}; } catch (_) { return {}; }
}

const sharedAssign = first('Assign Patient Code (Shared)');
const clinicAssign = first('Assign Patient Code (Clinic QR)');
const sharedUpsert = first('Upsert Patient (Shared)');
const clinicUpsert = first('Upsert Patient (Clinic QR)');
const sharedVisit = first('Insert Patient Visit (Shared)');

const assign = sharedAssign.patient_code ? sharedAssign : clinicAssign;
const upsert = sharedUpsert.patient_code ? sharedUpsert : clinicUpsert;
const visitId = sharedVisit.visit_id || clinicUpsert.visit_id || null;

return [{
  json: {
    patient_code: upsert.patient_code,
    visit_id: visitId,
    clinic_id: upsert.clinic_id || null,
    name: assign.name || upsert.name,
    phone: assign.phone || upsert.phone,
    clinic_name: assign.clinic_name,
    doctor_name: assign.doctor_name,
    visit_date: assign.visit_date,
  }
}];
